class Solution:
    def smallestValue(self, n: int) -> int:
        def sum_prime_factors(x):
            s = 0
            divisor = 2
            while divisor * divisor <= x:
                while x % divisor == 0:
                    s += divisor
                    x = x // divisor
                divisor += 1
            if x > 1:
                s += x
            return s

        current = n
        while True:
            s = sum_prime_factors(current)
            if s < current:
                current = s
            else:
                break
        return current

